static std::optional<APInt> foldBinOp(unsigned Opcode, const APInt &LHS,
                                     const APInt &RHS) {
  switch (Opcode) {
  case Instruction::Add:
    return LHS + RHS;
  case Instruction::Sub:
    return LHS - RHS;
  case Instruction::Mul:
    return LHS * RHS;
  case Instruction::SDiv:
    if (RHS.isZero())
      return std::nullopt;
    return LHS.sdiv(RHS);
  case Instruction::UDiv:
    if (RHS.isZero())
      return std::nullopt;
    return LHS.udiv(RHS);
  case Instruction::Shl:
    return LHS.shl(RHS);
  case Instruction::LShr:
    return LHS.lshr(RHS);
  case Instruction::AShr:
    return LHS.ashr(RHS);
  case Instruction::And:
    return LHS & RHS;
  case Instruction::Or:
    return LHS | RHS;
  case Instruction::Xor:
    return LHS ^ RHS;
  default:
    return std::nullopt;
  }
}

bool myConstantPropagation(Function &Foo) {
  if (Foo.empty())
    return false;

  bool Changed = false;
  SmallVector<Instruction *, 16> ToErase;

  for (BasicBlock &BB : Foo) {
    for (Instruction &I : BB) {
      if (!isa<BinaryOperator>(I))
        continue;

      // TODO: Remove this when the TODO is complete
      (void)ToErase;

      if (auto *LHS = dyn_cast<ConstantInt>(I.getOperand(0))) {
        if (auto *RHS = dyn_cast<ConstantInt>(I.getOperand(1))) {
          if (auto Result =
                  foldBinOp(I.getOpcode(), LHS->getValue(), RHS->getValue())) {
            Constant *C = ConstantInt::get(I.getType(), *Result);
            I.replaceAllUsesWith(C);
            ToErase.push_back(&I);
            Changed = true;
          }
        }
      }
    }
  }

  for (Instruction *I : ToErase)
    I->eraseFromParent();

  return Changed;
}

